package com.udayan.ocp;
 
import java.util.concurrent.*;
 
class MyCallable implements Callable<Integer> {
    private Integer i;
 
    public MyCallable(Integer i) {
        this.i = i;
    }
 
    public Integer call() throws Exception {
        return --i;
    }
}
 
class MyThread extends Thread {
    private int i;
 
    MyThread(int i) {
        this.i = i;
    }
 
    public void run() {
        i++;
    }
}
 
public class Test {
    public static void main(String[] args) throws ExecutionException, InterruptedException{
        ExecutorService es = Executors.newSingleThreadExecutor();
        MyCallable callable = new MyCallable(10);
        MyThread thread = new MyThread(10);
        System.out.println(es.submit(callable).get());
        System.out.println(es.submit(thread).get());
        es.shutdown();
    }
}

questions.explanation:
Method submit is overloaded to accept both Callable and Runnable: <T> Future<T> submit(Callable<T> task); and Future<?> submit(Runnable task);
Both returns a Future object. call() method of MyCallable returns 9 and get() method returns this value.
run() method of MyThread doesn't return anything, hence get() method of Future object returns null.

